mapper.sql:
WHERE 1 = 1

    AND M.MENU_ID = #{menuId}


    AND M.MENU_CODE LIKE CONCAT('%', #{menuCode}, '%')


    AND M.MENU_NAME LIKE CONCAT('%', #{menuName}, '%')


    AND M.PARENT_MENU_ID = #{parentMenuId}


    AND M.USE_YN = #{useYn}

mapper.select:
SELECT COUNT(*)
FROM MENU M
WHERE M.MENU_CODE = #{menuCode}

    AND M.MENU_ID != #{excludeMenuId}

mapper.insert:
INSERT INTO MENU (
    MENU_CODE
, MENU_NAME
, MENU_PATH
, PARENT_MENU_ID
, SORT_ORDER
, USE_YN
, CRT_DT
, UPD_DT
) VALUES (
             #{menuCode}
         , #{menuName}
         , #{menuPath}
         , #{parentMenuId}
         , #{sortOrder}
         , #{useYn}
         , NOW()
         , NOW()
         )

mapper.update:
UPDATE MENU
SET MENU_CODE      = #{menuCode}
  , MENU_NAME      = #{menuName}
  , MENU_PATH      = #{menuPath}
  , PARENT_MENU_ID = #{parentMenuId}
  , SORT_ORDER     = #{sortOrder}
  , USE_YN         = #{useYn}
  , UPD_DT         = NOW()
WHERE MENU_ID = #{menuId}

UPDATE MENU
SET PARENT_MENU_ID = #{parentMenuId,jdbcType=BIGINT}
  , SORT_ORDER     = #{sortOrder,jdbcType=INTEGER}
  , UPD_DT         = NOW()
WHERE MENU_ID = #{menuId}
